#include <bits/stdc++.h>
using namespace std;

int main() {
    string s;
    while (cin >> s && s != ".") {
        int n = s.size();
        for (int p = 1; p <= n; ++p) {
            if (n % p == 0) {
                bool ok = true;
                for (int i = 0; i < n; ++i) {
                    if (s[i] != s[i % p]) {
                        ok = false;
                        break;
                    }
                }
                if (ok) {
                    cout << n / p << endl;
                    break;
                }
            }
        }
    }
    return 0;
}
